namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t HARD_CAP_ELEMS = 16384;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    SoftmaxCustomTilingData tiling;
    const gert::Shape *x_shape = context->GetInputShape(0);
    const std::vector<int64_t> shape = x_shape->GetOriginShape().GetDims();
    uint32_t totalLength = 1;
    for (size_t i = 0; i < shape.size(); ++i) {
        totalLength *= static_cast<uint32_t>(shape[i]);
    }
    uint32_t rowLength = (shape.size() >= 2) ? static_cast<uint32_t>(shape[1]) : totalLength;
    uint32_t numRows = totalLength / rowLength;

    // UB budget: 3 local tensors (input, output, temp) each of tileLength floats -> 12 * tileLength bytes
    uint32_t maxTile = UB_BUDGET_BYTES / 12;
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    uint32_t tileLen = (rowLength < maxTile) ? AlignDown(rowLength, ALIGN_ELEMS) : maxTile;
    if (tileLen == 0) tileLen = rowLength;

    // blockDim: each block processes one or more rows; use numRows as hint
    uint32_t blockDim = numRows;
    if (blockDim > 256) blockDim = 256;   // limit
    if (blockDim < 1) blockDim = 1;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_rowLength(rowLength);
    tiling.set_numRows(numRows);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

